#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* generate_session_token() {
    char* token = malloc(17); // allocate memory for the token
    srand(time(NULL)); // seed the random number generator with the current time
    
    for (int i = 0; i < 16; i++) {
        int rand_num = rand() % 62; // get a random number between 0 and 62, inclusive
        if (rand_num < 10) { // if the random number is less than 10, it's a digit
            token[i] = '0' + rand_num; // add the corresponding digit to the token
        } else {
            token[i] = 'a' + (rand_num - 10); // otherwise, add the corresponding letter to the token
        }
    }
    
    return token; // return the generated token
}